import { createSlice, PayloadAction } from '@reduxjs/toolkit';

interface ErpSalesState {
  loading: boolean;
}

const erpSalesSlice = createSlice({
  name: 'erpSales',
  initialState: {
    loading: false,
  } as ErpSalesState,
  reducers: {
    setLoading(state, { payload }: PayloadAction<boolean>) {
      state.loading = payload;
    },
  },
});

export const { setLoading } = erpSalesSlice.actions;
export default erpSalesSlice.reducer;
