import React from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { SystemLogo } from '@linm-soft-org/linm-web-common-components';
import { showDevNav } from '../../dev/isStandalone';

/** MFE-local 404 — không dùng common-components NotFoundPage (cần root `auth` slice). */
export const SimpleNotFoundPage: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const home = showDevNav ? '/dev' : '/bh/dh';

  return (
    <div style={{ padding: '2rem', maxWidth: 480, margin: '0 auto', textAlign: 'center' }}>
      <SystemLogo size={64} />
      <h1 style={{ fontSize: '3rem', margin: '0 0 0.5rem' }}>404</h1>
      <p>
        Trang <code>{location.pathname}</code> không tồn tại.
      </p>
      <div style={{ display: 'flex', gap: 12, justifyContent: 'center', marginTop: 24 }}>
        <button type="button" onClick={() => navigate(home, { replace: true })}>
          Về trang chủ
        </button>
        <button type="button" onClick={() => navigate(-1)}>
          Quay lại
        </button>
        {showDevNav && (
          <Link to="/dev">Dev Navigation</Link>
        )}
      </div>
    </div>
  );
};
